function esc(v){return String(v==null?'':v).replace(/[&<>'"]/g,c=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c]));}function n(v){v=Number(v);return Number.isFinite(v)?v:0}function fmt(v,d=0){return n(v).toLocaleString('en-US',{maximumFractionDigits:d,minimumFractionDigits:d})}function money(v,c='EGP'){return fmt(v,2)+' '+esc(c||'EGP')}function date10(v){return String(v||'').slice(0,10)}function today(){const d=new Date(),m=String(d.getMonth()+1).padStart(2,'0'),day=String(d.getDate()).padStart(2,'0');return d.getFullYear()+'-'+m+'-'+day}function addDays(s,d){const x=new Date(s+'T12:00:00');x.setDate(x.getDate()+d);return x.toISOString().slice(0,10)}function daysInclusive(from,to){if(!from||!to||to<from)return 0;return Math.floor((new Date(to+'T12:00:00')-new Date(from+'T12:00:00'))/86400000)+1}function perm(k){const u=(SESSION&&SESSION.user)||{},sp=(DATA&&DATA.permissions)||{};return !!(u.is_admin||(u.mountain&&u.mountain.permissions&&(u.mountain.permissions.all||u.mountain.permissions[k]))||sp.all||sp[k])}function showLoader(text){$('loaderText').textContent=text||L('جارٍ التحميل...','Loading...');$('loader').classList.add('show')}function hideLoader(){$('loader').classList.remove('show')}function toast(msg,bad){const el=$('toast');el.textContent=msg;el.className='toast show'+(bad?' bad':'');setTimeout(()=>el.classList.remove('show'),4200)}
